import { useState, useEffect } from "react";
import {
  useUpdate,
  useDelete,
  useGetIdentity,
  useRedirect,
  useRefresh,
  useNotify,
  useDataProvider,
} from "react-admin";
import { AdminButton } from "@/components/admin/AdminButton";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { notificationMessages } from "@/atomic-crm/constants/notificationMessages";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { KeyRound, Trash2, ShieldCheck } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import type { RegenerateCodeResult } from "@/atomic-crm/providers/supabase/extensions/types";
// NOTE: Client-side validation removed (2025-12-12)
// Edge Function /users PATCH handles validation with patchUserSchema
// salesService.salesUpdate() filters empty strings before sending to Edge Function
// Having duplicate validation here caused 400 errors from empty string avatar_url
import { invalidateIdentityCache } from "../providers/supabase/authProvider";
import { salesPermissionsSchema } from "@/atomic-crm/validation/sales";
import { UserDisableReassignDialog } from "./UserDisableReassignDialog";
import type { Sale } from "@/atomic-crm/types";

interface SalesPermissionsTabProps {
  record: Sale;
  mode: "view" | "edit";
  onModeToggle?: () => void;
  onDirtyChange?: (isDirty: boolean) => void;
}

/**
 * SalesPermissionsTab - User permissions and role management
 *
 * Displays and allows editing of:
 * - Role (admin, manager, rep)
 * - Administrator toggle (linked to admin role)
 * - Disabled status
 *
 * View mode: Read-only display with badges
 * Edit mode: Inline form with dropdowns and switches
 */
export function SalesPermissionsTab({
  record,
  mode,
  onModeToggle,
  onDirtyChange,
}: SalesPermissionsTabProps) {
  const [update, { isLoading }] = useUpdate();
  const [deleteOne, { isPending: isDeleting }] = useDelete();
  const notify = useNotify();
  const redirect = useRedirect();
  const refresh = useRefresh();
  const { data: identity } = useGetIdentity();
  // FIX [WF-C04]: Show reassign dialog before disabling user
  const [showDisableDialog, setShowDisableDialog] = useState(false);
  const [isResettingPassword, setIsResettingPassword] = useState(false);
  const [isGeneratingCode, setIsGeneratingCode] = useState(false);
  const [setupCodeResult, setSetupCodeResult] = useState<RegenerateCodeResult | null>(null);
  const [copiedOtp, setCopiedOtp] = useState(false);
  const dataProvider = useDataProvider() as ReturnType<typeof useDataProvider> & {
    resetUserPassword?: (targetEmail: string) => Promise<{ success: boolean }>;
    regenerateSetupCode?: (targetEmail: string) => Promise<RegenerateCodeResult>;
  };

  // Form state
  // Per Engineering Constitution #5: Form defaults from schema
  // Extract only the fields the schema expects (strictObject rejects unknown keys)
  const [formData, setFormData] = useState(() =>
    salesPermissionsSchema.parse({
      role: record.role,
      disabled: record.disabled,
    })
  );

  const [errors, setErrors] = useState<Record<string, string>>({});

  // Track dirty state for ResourceSlideOver's Save button
  // Since this component uses local useState (not react-hook-form),
  // we manually compare formData with original record values
  useEffect(() => {
    if (mode !== "edit" || !onDirtyChange) return;

    const isDirty = formData.role !== record.role || formData.disabled !== record.disabled;

    onDirtyChange(isDirty);
  }, [formData, record, mode, onDirtyChange]);

  // Prevent editing own account
  const isSelfEdit = record?.id === identity?.id;

  // Admin-initiated password reset: sends recovery email to target user
  const handleResetPassword = async () => {
    if (!record?.email || !dataProvider.resetUserPassword) return;

    try {
      setIsResettingPassword(true);
      await dataProvider.resetUserPassword(record.email);
      notify(`Password reset email sent to ${record.email}`, { type: "success" });
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : "Failed to send reset email";
      notify(message, { type: "error" });
    } finally {
      setIsResettingPassword(false);
    }
  };

  // Generate setup code (OTP) for user to set/reset password via /welcome page
  const handleGenerateCode = async () => {
    if (!record?.email || !dataProvider.regenerateSetupCode) return;

    try {
      setIsGeneratingCode(true);
      const result = await dataProvider.regenerateSetupCode(record.email);
      setSetupCodeResult(result);
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : "Failed to generate setup code";
      notify(message, { type: "error" });
    } finally {
      setIsGeneratingCode(false);
    }
  };

  const handleCopyOtp = () => {
    if (setupCodeResult?.emailOtp) {
      navigator.clipboard.writeText(setupCodeResult.emailOtp).then(() => {
        setCopiedOtp(true);
        setTimeout(() => setCopiedOtp(false), 2000);
      });
    }
  };

  // Remove user (soft-delete handled by Data Provider layer)
  const handleRemoveUser = () => {
    if (isSelfEdit) {
      notify("You cannot remove your own account", { type: "warning" });
      return;
    }

    // useDelete hook handles soft-delete conversion via Data Provider
    // The withSkipDelete wrapper intercepts and sets deleted_at automatically
    deleteOne(
      "sales",
      { id: record.id, previousData: record },
      {
        onSuccess: () => {
          notify(notificationMessages.deleted("User"), { type: "success" });
          refresh();
          redirect("/sales");
        },
        onError: (error: unknown) => {
          const message = error instanceof Error ? error.message : "Failed to remove user";
          notify(message, { type: "error" });
        },
      }
    );
  };

  // Update form field
  const handleChange = (field: string, value: "admin" | "manager" | "rep" | boolean) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors((prev) => {
        const newErrors = { ...prev };
        delete newErrors[field];
        return newErrors;
      });
    }
  };

  /**
   * Handle disabled toggle change
   * FIX [WF-C04]: When disabling, show reassign dialog instead of direct toggle
   * Re-enabling doesn't require reassignment
   */
  const handleDisabledChange = (checked: boolean) => {
    if (checked && !record.disabled) {
      // User is trying to DISABLE → show reassignment dialog
      setShowDisableDialog(true);
    } else {
      // User is RE-ENABLING → direct toggle is fine
      handleChange("disabled", checked);
    }
  };

  /**
   * Handle successful disable from dialog
   * Updates local form state to reflect the disabled status
   */
  const handleDisableSuccess = () => {
    setFormData((prev) => ({ ...prev, disabled: true }));
    if (onModeToggle) onModeToggle(); // Switch back to view mode
  };

  // Save changes
  const handleSave = async () => {
    try {
      // NOTE: Client-side validation removed - Edge Function validates
      // salesService.salesUpdate() filters empty strings before sending

      // Update record - CRITICAL: previousData required by ra-data-postgrest's getChanges()
      await update(
        "sales",
        { id: record.id, data: formData, previousData: record },
        {
          returnPromise: true,
          onSuccess: () => {
            // If role changed, invalidate cache so user sees new permissions immediately
            if (formData.role !== record.role) {
              invalidateIdentityCache();
            }
            notify(notificationMessages.updated("Permissions"), { type: "success" });
            if (onModeToggle) onModeToggle(); // Switch back to view mode
          },
          onError: (error: Error) => {
            notify(error.message || "Failed to update permissions", { type: "error" });
            const errorWithErrors = error as Error & { errors?: Record<string, string> };
            if (errorWithErrors.errors) {
              setErrors(errorWithErrors.errors);
            }
          },
        }
      );
    } catch (error: unknown) {
      const errorWithErrors = error as Error & { errors?: Record<string, string> };
      if (errorWithErrors.errors) {
        setErrors(errorWithErrors.errors);
        notify("Validation failed. Please check the form.", { type: "warning" });
      } else {
        notify("An error occurred", { type: "error" });
      }
    }
  };

  // Get role badge styling
  const getRoleBadge = (role: string) => {
    switch (role) {
      case "admin":
        return (
          <Badge variant="outline" className="border-primary text-primary">
            Admin
          </Badge>
        );
      case "manager":
        return (
          <Badge variant="outline" className="border-success text-success">
            Manager
          </Badge>
        );
      case "rep":
        return (
          <Badge variant="outline" className="border-muted-foreground text-muted-foreground">
            Rep
          </Badge>
        );
      default:
        return null;
    }
  };

  // Form submit handler for the footer button
  const handleFormSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isSelfEdit) {
      handleSave();
    }
  };

  if (!record) {
    return (
      <div className="space-y-4">
        <Skeleton className="h-11 w-full" />
        <Skeleton className="h-11 w-full" />
        <Skeleton className="h-11 w-full" />
      </div>
    );
  }

  const content = (
    <div className="space-y-6">
      {/* Self-edit warning */}
      {isSelfEdit && mode === "edit" && (
        <div className="p-3 border border-warning bg-warning/10 rounded-md">
          <p className="text-sm text-warning-foreground">
            <strong>Note:</strong> You cannot modify your own permissions.
          </p>
        </div>
      )}

      {/* Role field */}
      <div>
        <Label htmlFor="role">Role</Label>
        {mode === "view" ? (
          <div className="mt-2">{getRoleBadge(record.role)}</div>
        ) : (
          <>
            <Select
              value={formData.role}
              onValueChange={(value) => handleChange("role", value as "admin" | "manager" | "rep")}
              disabled={isLoading || isSelfEdit}
            >
              <SelectTrigger id="role" className={errors.role ? "border-destructive" : ""}>
                <SelectValue placeholder="Select role" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="rep">Rep</SelectItem>
                <SelectItem value="manager">Manager</SelectItem>
                <SelectItem value="admin">Admin</SelectItem>
              </SelectContent>
            </Select>
            {errors.role && <p className="text-sm text-destructive mt-1">{errors.role}</p>}
            <p className="text-sm text-muted-foreground mt-1">
              Rep: Edit own records. Manager: Edit all records. Admin: Full system access.
            </p>
          </>
        )}
      </div>

      {/* Administrator toggle (computed from role) */}
      <div>
        <Label htmlFor="administrator">Administrator Access</Label>
        {mode === "view" ? (
          <p className="text-sm text-foreground mt-1">
            {record.administrator || record.role === "admin" ? "Yes" : "No"}
          </p>
        ) : (
          <div className="mt-2">
            <div className="flex items-center gap-3 p-3 border border-border rounded-md bg-muted/20">
              <Switch
                id="administrator"
                checked={formData.role === "admin"}
                onCheckedChange={(checked) => handleChange("role", checked ? "admin" : "rep")}
                disabled={isLoading || isSelfEdit}
              />
              <div className="flex-1">
                <p className="text-sm font-medium">
                  {formData.role === "admin" ? "Enabled" : "Disabled"}
                </p>
                <p className="text-xs text-muted-foreground">
                  Administrator access is automatically granted to users with Admin role
                </p>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Disabled status */}
      <div>
        <Label htmlFor="disabled">Account Status</Label>
        {mode === "view" ? (
          <div className="mt-2">
            {record.disabled ? (
              <Badge variant="outline" className="border-warning text-warning">
                Disabled
              </Badge>
            ) : (
              <Badge variant="outline" className="border-success text-success">
                Active
              </Badge>
            )}
          </div>
        ) : (
          <div className="mt-2">
            <div className="flex items-center gap-3 p-3 border border-border rounded-md bg-muted/20">
              <Switch
                id="disabled"
                checked={formData.disabled}
                onCheckedChange={handleDisabledChange}
                disabled={isLoading || isSelfEdit}
              />
              <div className="flex-1">
                <p className="text-sm font-medium">
                  {formData.disabled ? "Account Disabled" : "Account Active"}
                </p>
                <p className="text-xs text-muted-foreground">
                  Disabled accounts cannot log in or access the system
                </p>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Warning for disabled accounts */}
      {mode === "edit" && formData.disabled && !isSelfEdit && (
        <div className="p-3 border border-warning bg-warning/10 rounded-md">
          <p className="text-sm text-warning-foreground">
            <strong>Warning:</strong> Disabling this account will prevent the user from logging in.
          </p>
        </div>
      )}

      {/* Password Management (admin only, not self, both view and edit modes) */}
      {!isSelfEdit && identity?.role === "admin" && (
        <div className="mt-6 pt-6 border-t border-border">
          <div className="p-4 border border-border rounded-lg bg-muted/20 space-y-4">
            <h3 className="text-sm font-semibold">Password Management</h3>

            {/* Generate Setup Code */}
            <div>
              <p className="text-sm text-muted-foreground mb-2">
                Generate a setup code for this user to set or reset their password.
              </p>
              <AlertDialog>
                <AlertDialogTrigger asChild>
                  <AdminButton
                    variant="outline"
                    size="sm"
                    disabled={isGeneratingCode}
                    isLoading={isGeneratingCode}
                    loadingText="Generating..."
                    className="gap-2"
                  >
                    <ShieldCheck className="h-4 w-4" />
                    Generate Setup Code
                  </AdminButton>
                </AlertDialogTrigger>
                <AlertDialogContent>
                  <AlertDialogHeader>
                    <AlertDialogTitle>Generate Setup Code</AlertDialogTitle>
                    <AlertDialogDescription>
                      Generate a new 6-digit setup code for{" "}
                      <strong>
                        {record?.first_name} {record?.last_name}
                      </strong>{" "}
                      ({record?.email})? Any previous code will be invalidated.
                    </AlertDialogDescription>
                  </AlertDialogHeader>
                  <AlertDialogFooter>
                    <AlertDialogCancel>Cancel</AlertDialogCancel>
                    <AlertDialogAction onClick={handleGenerateCode}>Generate</AlertDialogAction>
                  </AlertDialogFooter>
                </AlertDialogContent>
              </AlertDialog>
            </div>

            <div className="border-t border-border pt-4">
              <p className="text-sm text-muted-foreground mb-2">
                Or send a recovery email directly (may be blocked by email security).
              </p>
              <AlertDialog>
                <AlertDialogTrigger asChild>
                  <AdminButton
                    variant="outline"
                    size="sm"
                    disabled={isResettingPassword}
                    isLoading={isResettingPassword}
                    loadingText="Sending..."
                    className="gap-2"
                  >
                    <KeyRound className="h-4 w-4" />
                    Send Reset Email
                  </AdminButton>
                </AlertDialogTrigger>
                <AlertDialogContent>
                  <AlertDialogHeader>
                    <AlertDialogTitle>Send Password Reset Email</AlertDialogTitle>
                    <AlertDialogDescription>
                      Send a password reset email to{" "}
                      <strong>
                        {record?.first_name} {record?.last_name}
                      </strong>{" "}
                      ({record?.email})?
                    </AlertDialogDescription>
                  </AlertDialogHeader>
                  <AlertDialogFooter>
                    <AlertDialogCancel>Cancel</AlertDialogCancel>
                    <AlertDialogAction onClick={handleResetPassword}>Send</AlertDialogAction>
                  </AlertDialogFooter>
                </AlertDialogContent>
              </AlertDialog>
            </div>
          </div>
        </div>
      )}

      {/* Setup Code Dialog */}
      <Dialog open={!!setupCodeResult} onOpenChange={(open) => !open && setSetupCodeResult(null)}>
        <DialogContent className="sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>Setup Code Generated</DialogTitle>
            <DialogDescription>
              Share this code with {record?.first_name} {record?.last_name} to set their password.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <p className="text-sm text-muted-foreground">Setup code:</p>
            <div className="flex items-center gap-3">
              <div className="flex-1 rounded-md border border-input bg-muted px-4 py-3 text-center font-mono text-2xl tracking-[0.3em] select-all">
                {setupCodeResult?.emailOtp}
              </div>
              <Button
                type="button"
                variant="outline"
                className="shrink-0 cursor-pointer"
                onClick={handleCopyOtp}
              >
                {copiedOtp ? "Copied!" : "Copy"}
              </Button>
            </div>
            <p className="text-sm text-muted-foreground">
              Setup URL:{" "}
              <span className="font-mono text-foreground">{window.location.origin}/#/welcome</span>
            </p>
            <p className="text-xs text-muted-foreground">
              Tell the user: &quot;Go to the URL above and enter your email with this code.&quot;
            </p>
          </div>
          <DialogFooter>
            <Button
              type="button"
              className="cursor-pointer"
              onClick={() => setSetupCodeResult(null)}
            >
              Done
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Danger Zone - Remove User (admin only, not self) */}
      {!isSelfEdit && identity?.role === "admin" && (
        <div className="mt-8 pt-6 border-t border-destructive/30">
          <div className="p-4 border border-destructive/30 rounded-lg bg-destructive/5">
            <h3 className="text-sm font-semibold text-destructive mb-2">Danger Zone</h3>
            <p className="text-sm text-muted-foreground mb-4">
              Removing a user will prevent them from accessing the system. This action can be undone
              by an administrator.
            </p>
            <AlertDialog>
              <AlertDialogTrigger asChild>
                <AdminButton
                  variant="destructive"
                  size="sm"
                  disabled={isDeleting}
                  className="gap-2"
                >
                  <Trash2 className="h-4 w-4" />
                  {isDeleting ? "Removing..." : "Remove User"}
                </AdminButton>
              </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>Remove User</AlertDialogTitle>
                  <AlertDialogDescription>
                    Are you sure you want to remove{" "}
                    <strong>
                      {record?.first_name} {record?.last_name}
                    </strong>{" "}
                    ({record?.email})?
                    <br />
                    <br />
                    They will no longer be able to log in or access the system. This can be undone
                    later if needed.
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                  <AlertDialogCancel>Cancel</AlertDialogCancel>
                  <AlertDialogAction
                    onClick={handleRemoveUser}
                    className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                  >
                    Remove User
                  </AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>
          </div>
        </div>
      )}
    </div>
  );

  // In edit mode, wrap with form so footer "Save Changes" button works
  if (mode === "edit") {
    return (
      <>
        <form id="slide-over-edit-form" onSubmit={handleFormSubmit}>
          {content}
        </form>
        {/* FIX [WF-C04]: Disable user reassignment dialog */}
        <UserDisableReassignDialog
          user={record}
          open={showDisableDialog}
          onClose={() => setShowDisableDialog(false)}
          onSuccess={handleDisableSuccess}
        />
      </>
    );
  }

  return content;
}
